INSERT INTO `broadcasts` (`id`, `title`, `message`, `segment`, `platform`, `link`, `attachment`, `sender_id`, `target_count`, `status`, `created_at`, `updated_at`) VALUES
(1, 'Halo', 'halo', 'trainer', 'email', NULL, NULL, 1, 3, 'sent', '2026-05-12 03:39:16', '2026-05-12 03:39:16'),
(2, 'UNDANGAN WORKSHOP OBE TEACHING & LEARNING SYSTEM', 'Yth. Bapak/Ibu Pimpinan, Dekan, Wakil Dekan, Kepala Program Studi, dan Dosen\r\ndi Tempat\r\n\r\nDengan hormat,\r\n\r\nSalam sejahtera.\r\n\r\nSehubungan dengan akan diselenggarakannya Workshop OBE Teaching & Learning System: Designing Learning Experiences to Develop Real Competencies and Professional Portfolios, bersama email ini kami sampaikan surat undangan resmi beserta flyer kegiatan sebagai informasi dan ajakan untuk berpartisipasi dalam workshop tersebut.\r\n\r\n📅 Informasi Kegiatan\r\n\r\nHari/Tanggal: Kamis–Jumat, 30–31 Juli 2026\r\nWaktu: 09.00 s.d. 16.30 WIB\r\nTempat: Aula Lt. 4, Fakultas Ilmu Terapan, Telkom University\r\n\r\n💰 Biaya Partisipasi\r\nRp 800.000,- / peserta\r\n\r\n🎁 Benefit Peserta\r\n\r\nSertifikat\r\nModul\r\nToolkit\r\nCoffee Break\r\nLunch\r\nDoorprize\r\nGratis Sertifikat Kompetensi BNSP\r\n\r\n📝 Link Registrasi:\r\nhttps://bit.ly/daftar-workshop-OBE\r\n\r\n📌 Kuota Terbatas!\r\nHanya tersedia untuk 50 peserta, sehingga kami mengimbau Bapak/Ibu untuk segera melakukan pendaftaran.\r\n\r\nApabila memerlukan informasi lebih lanjut, silakan menghubungi:\r\nNur Ibrahim (WhatsApp): +62 851-1103-5835\r\n\r\nDemikian undangan ini kami sampaikan. Besar harapan kami agar Bapak/Ibu dapat berpartisipasi dalam kegiatan ini. Atas perhatian dan kerja sama yang baik, kami ucapkan terima kasih.\r\n\r\nHormat kami,\r\n\r\nPanitia Workshop OBE Teaching & Learning System\r\nAPTIKOM Jawa Barat × Telkom University', 'manual', 'email', NULL, '[\"broadcasts\\/1781238902_Surat_Undangan_Workshop_OBTL_Aptikom_Jabar.pdf\",\"broadcasts\\/1781238902_flyer.jpeg\"]', 1, 3, 'sent', '2026-06-12 04:35:02', '2026-06-12 04:35:02'),
(3, 'Undangan Workshop OBE Teaching & Learning System – Pendaftaran Dibuka!', 'Yth. Bapak/Ibu Dosen Universitas Telkom\r\ndi Tempat\r\n\r\nDengan hormat,\r\n\r\nSalam sejahtera.\r\n\r\nSehubungan dengan akan diselenggarakannya Workshop OBE Teaching & Learning System: Designing Learning Experiences to Develop Real Competencies and Professional Portfolios, bersama email ini kami sampaikan surat undangan resmi beserta flyer kegiatan sebagai informasi dan ajakan untuk berpartisipasi dalam workshop tersebut.\r\n\r\n📅 Informasi Kegiatan\r\n\r\nHari/Tanggal: Kamis–Jumat, 30–31 Juli 2026\r\nWaktu: 09.00 s.d. 16.30 WIB\r\nTempat: Aula Lt. 4, Fakultas Ilmu Terapan, Telkom University\r\n\r\n💰 Biaya Partisipasi\r\nRp 800.000,- / peserta\r\n\r\n🎁 Benefit Peserta\r\n\r\nSertifikat\r\nModul\r\nToolkit\r\nCoffee Break\r\nLunch\r\nDoorprize\r\nGratis Sertifikat Kompetensi BNSP\r\n\r\n📝 Link Registrasi:\r\nhttps://bit.ly/daftar-workshop-OBE\r\n\r\n📌 Kuota Terbatas!\r\nHanya tersedia untuk 50 peserta, sehingga kami mengimbau Bapak/Ibu untuk segera melakukan pendaftaran.\r\n\r\nApabila memerlukan informasi lebih lanjut, silakan menghubungi:\r\nNur Ibrahim (WhatsApp): +62 851-1103-5835\r\n\r\nDemikian undangan ini kami sampaikan. Besar harapan kami agar Bapak/Ibu dapat berpartisipasi dalam kegiatan ini. Atas perhatian dan kerja sama yang baik, kami ucapkan terima kasih.\r\n\r\nHormat kami,\r\n\r\nPanitia Workshop OBE Teaching & Learning System\r\nAPTIKOM Jawa Barat × Telkom University', 'manual', 'email', NULL, '[\"broadcasts\\/1781239275_Surat_Undangan_Workshop_OBTL_Aptikom_Jabar.pdf\",\"broadcasts\\/1781239275_flyer.jpeg\"]', 1, 1, 'sent', '2026-06-12 04:41:15', '2026-06-12 04:41:15');
