(13, 'Mobile programmer testing', 4, 1, 1, NULL, NULL, NULL, NULL, NULL, 'blablablablablablblabla blablablablablablblabla blablablablablablblabla blablablablablablblabla blablablablablablblabla blablablablablablblabla blablablablablablblabla blablablablablablblabla blablablablablablblabla blablablablablablblabla blablablablablablblabla blablablablablablblabla', 'beginner', 100000, 'limit_2', 10, '2026-05-06', '2026-05-09', '[{\"item\":\"Edit Video\",\"quantity\":2,\"unit_price\":15000,\"total\":30000}]', 0, 'archive', NULL, 'template_4', '[]', '[]', 'courses/ClKoagHqNzYIT3tnhNfQcR6tSynQiXC2JkOJCTAn.png', 'image', '2026-05-06 08:30:03', '2026-06-08 07:02:42', 'courses/card_thumbnails/MeezfHDGav6yDbuylO9ZYBef4nyKgOPis151fTnr.png', NULL, '2026-05-06 08:32:58', NULL, 1, 0),
(14, 'Fundamental hingga Implementasi Data Science: Dari Data Mentah Menjadi Insight Bernilai.', 3, 1, 1, NULL, NULL, NULL, NULL, NULL, 'Course ini dirancang untuk memberikan pemahaman menyeluruh mengenai konsep dan praktik Data Science, mulai dari pengenalan data, proses pengolahan, analisis, hingga visualisasi dan penerapan model sederhana. Peserta akan mempelajari bagaimana data dikumpulkan, dibersihkan, dianalisis, dan diinterpretasikan untuk menghasilkan insight yang berguna dalam pengambilan keputusan. Dengan pendekatan bertahap dan praktis, course ini cocok bagi pemula yang ingin masuk ke dunia Data Science secara terstruktur.', 'intermediate', 150000, 'limit_2', 5, '2026-05-06', '2026-05-09', '[{\"item\":\"Edit Video\",\"quantity\":5,\"unit_price\":14997,\"total\":74985}]', 0, 'archive', NULL, NULL, NULL, NULL, 'courses/5xdOE5apUkVZqlQWzVW7rUKUa93LSYbtugQ8v6mN.png', 'image', '2026-05-06 09:17:52', '2026-06-08 10:37:45', 'courses/card_thumbnails/xia2KD1IEWhenfOWR5MVmJjEsMCHqXJ5m7OnrTkM.png', NULL, '2026-05-06 10:04:15', NULL, 1, 0),
(15, 'Machine Learning Basics', 10, 1, 1, NULL, NULL, NULL, NULL, NULL, 'Course Machine Learning Basics dirancang untuk membantu peserta memahami dasar-dasar machine learning secara bertahap mulai dari konsep umum, pengolahan data, hingga penerapan model sederhana. Materi disusun secara berurutan agar peserta dapat memahami bagaimana data diproses menjadi sebuah sistem cerdas yang mampu melakukan prediksi dan pengambilan keputusan secara otomatis. Dalam course ini peserta akan mempelajari konsep machine learning, tahapan pengolahan data, jenis algoritma dasar, serta implementasi sederhana machine learning dalam kehidupan sehari-hari. Course ini cocok untuk pemula yang ingin memulai perjalanan di bidang Artificial Intelligence dan Data Science.', 'beginner', 100000, 'limit_2', 5, '2026-05-06', '2026-05-09', '[{\"item\":\"Edit Video\",\"quantity\":3,\"unit_price\":15000,\"total\":45000}]', 0, 'archive', NULL, NULL, NULL, NULL, 'courses/AwAQ1XdfI67R0A9EZBw0xpQoO0kmhEBMr5oxcjFJ.png', 'image', '2026-05-06 10:16:18', '2026-06-08 10:37:42', 'courses/card_thumbnails/s6elNfCmM757vTMa3e1SiGYDw7Bcatbq4KOjVgsl.png', NULL, '2026-05-06 10:36:28', NULL, 1, 0),
(16, 'Digital Marketing Fundamentals', 11, 1, 1, NULL, NULL, NULL, NULL, NULL, 'Course Digital Marketing Fundamentals dirancang untuk membantu peserta memahami konsep dasar pemasaran digital secara bertahap mulai dari pengenalan digital marketing, strategi pemasaran melalui media sosial, hingga optimalisasi konten dan analisis performa pemasaran. Materi disusun secara terstruktur agar peserta dapat memahami bagaimana bisnis memanfaatkan platform digital untuk meningkatkan brand awareness, menjangkau target pasar, serta meningkatkan penjualan produk atau layanan. Course ini cocok untuk pemula, pelaku UMKM, mahasiswa, maupun siapa saja yang ingin mempelajari strategi pemasaran digital di era modern.', 'beginner', 0, 'all', 0, NULL, NULL, NULL, 0, 'archive', NULL, NULL, NULL, NULL, 'courses/iK2yH2Yq0ehcACsQMV8Gj3OJR5T0W7qrZphw1Eps.png', 'image', '2026-05-06 10:46:59', '2026-05-07 03:11:11', 'courses/card_thumbnails/PUaBN5UyZhlp9D5icRswgZgKoBRQ76iUeW1yh8UK.png', NULL, '2026-05-06 11:05:39', NULL, 1, 0),
