(122, 13, 5, 'Module 2 - Video Lesson', NULL, 0, 'approved', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, '2026-05-06 08:32:58', 1, NULL, 'video', 'courses/13/materials/1778056309_1777307263_WhatsApp_Video_2026-04-22_at_11.12.59.mp4', '1777307263_WhatsApp_Video_2026-04-22_at_11.12.59.mp4', 'video/mp4', 582243, 0, 0, '2026-05-06 08:30:03', '2026-05-06 08:32:58'),
(123, 13, 6, 'Module 2 - Quiz', NULL, 0, 'approved', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, '2026-05-06 08:32:58', 1, NULL, 'quiz', 'quiz_submitted', NULL, NULL, 0, 0, 0, '2026-05-06 08:30:03', '2026-05-06 08:32:58'),
(124, 14, 1, 'Module 1 - Material', '<p class=\"MsoNormal\" style=\"margin: 0cm 0cm 8pt; line-height: normal; font-size: 12pt; font-family: Aptos, sans-serif; color: rgb(0, 0, 0);\"><span style=\"font-family: &quot;Times New Roman&quot;, serif;\">Pada modul ini, peserta akan diperkenalkan dengan konsep dasar Data Science serta pentingnya peran data dalam kehidupan modern. Data Science merupakan bidang interdisipliner yang menggabungkan statistik, matematika, dan ilmu komputer untuk mengekstrak informasi dari data. Di era digital saat ini, hampir semua aktivitas menghasilkan data, mulai dari penggunaan media sosial, transaksi online, hingga sistem informasi perusahaan. Peserta akan memahami jenis-jenis data, seperti data terstruktur dan tidak terstruktur, serta bagaimana data tersebut dikumpulkan melalui berbagai sumber seperti database, API, atau sensor digital. Selain itu, modul ini juga membahas peran seorang data scientist, termasuk kemampuan yang dibutuhkan seperti analisis, pemrograman, dan komunikasi data.<o:p></o:p></span></p><p class=\"MsoNormal\" style=\"margin: 0cm 0cm 8pt; line-height: normal; font-size: 12pt; font-family: Aptos, sans-serif; color: rgb(0, 0, 0);\"><span style=\"font-family: &quot;Times New Roman&quot;, serif;\">Selanjutnya, peserta akan dikenalkan dengan alur kerja Data Science (data science workflow), yang mencakup tahap pengumpulan data, pembersihan data, eksplorasi, pemodelan, hingga visualisasi. Dengan memahami alur ini, peserta dapat melihat gambaran besar bagaimana sebuah proyek Data Science dilakukan dari awal hingga akhir. Modul ini juga menekankan pentingnya etika dalam penggunaan data, seperti privasi dan keamanan data pengguna. Dengan demikian, peserta tidak hanya memahami aspek teknis, tetapi juga tanggung jawab dalam mengelola data.<o:p></o:p></span></p>', 0, 'approved', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, '2026-05-06 10:03:58', 1, NULL, 'pdf', '', NULL, NULL, 0, 0, 0, '2026-05-06 09:17:52', '2026-05-06 10:03:58'),
(125, 14, 2, 'Module 1 - Video Lesson', NULL, 0, 'approved', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, '2026-05-06 10:03:58', 1, NULL, 'video', 'courses/14/materials/1778059423_1777307263_WhatsApp_Video_2026-04-22_at_11.12.59.mp4', '1777307263_WhatsApp_Video_2026-04-22_at_11.12.59.mp4', 'video/mp4', 582243, 0, 0, '2026-05-06 09:17:52', '2026-05-06 10:03:58'),
